mapper.sql:
SELECT
ID,
DEBTORPAYMENT_ID,
SERIAL_NUMBER,
INVOICE_PREPAY_ID,
INVOICE_PREPAY_NO,
SYS_INVOICE_PREPAY_NO,
"TYPE",
INVOICE_PREPAY_AMOUNT,
DEBTORPAY_PAYMENT_TYPE_CODE,
DEBTORPAY_PAYMENT_TYPE_NAME,
PAYMENT_METHOD_CODE,
PAYMENT_METHOD_NAME,
FILE_NO,
FILE_TIME,
REMARK,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_DEBTORPAYMENT_DETAIL


        and ID = #{id}


        and DEBTORPAYMENT_ID = #{debtorpaymentId}


        and SERIAL_NUMBER = #{serialNumber}


        and INVOICE_PREPAY_ID = #{invoicePrepayId}


        and INVOICE_PREPAY_NO = #{invoicePrepayNo}


        and SYS_INVOICE_PREPAY_NO = #{sysInvoicePrepayNo}


        and "TYPE" = #{type}


        and INVOICE_PREPAY_AMOUNT = #{invoicePrepayAmount}


        and DEBTORPAY_PAYMENT_TYPE_CODE = #{debtorpayPaymentTypeCode}


        and DEBTORPAY_PAYMENT_TYPE_NAME = #{debtorpayPaymentTypeName}


        and PAYMENT_METHOD_CODE = #{paymentMethodCode}


        and PAYMENT_METHOD_NAME = #{paymentMethodName}


        and FILE_NO = #{fileNo}


        and FILE_TIME = #{fileTime}


        and REMARK = #{remark}

mapper.select:
SELECT ID, DEBTORPAYMENT_ID, SERIAL_NUMBER, INVOICE_PREPAY_ID, INVOICE_PREPAY_NO, SYS_INVOICE_PREPAY_NO, "TYPE", INVOICE_PREPAY_AMOUNT, DEBTORPAY_PAYMENT_TYPE_CODE, DEBTORPAY_PAYMENT_TYPE_NAME, PAYMENT_METHOD_CODE, PAYMENT_METHOD_NAME, FILE_NO, FILE_TIME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_FD_DEBTORPAYMENT_DETAIL
DEBTORPAYMENT_ID = #{id}
ORDER BY SERIAL_NUMBER ASC

mapper.insert:
INSERT INTO T_FD_DEBTORPAYMENT_DETAIL ( ID, DEBTORPAYMENT_ID, SERIAL_NUMBER, INVOICE_PREPAY_ID, INVOICE_PREPAY_NO, SYS_INVOICE_PREPAY_NO, "TYPE", INVOICE_PREPAY_AMOUNT, DEBTORPAY_PAYMENT_TYPE_CODE, DEBTORPAY_PAYMENT_TYPE_NAME, PAYMENT_METHOD_CODE, PAYMENT_METHOD_NAME, FILE_NO, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, BANK_ID, BANK_NAME) (
SELECT #{item.id, jdbcType=BIGINT}, #{item.debtorpaymentId, jdbcType=BIGINT}, #{item.serialNumber,jdbcType=INTEGER}, #{item.invoicePrepayId, jdbcType=BIGINT}, #{item.invoicePrepayNo, jdbcType=VARCHAR}, #{item.sysInvoicePrepayNo, jdbcType=VARCHAR}, #{item.type, jdbcType=BIGINT}, #{item.invoicePrepayAmount, jdbcType=DECIMAL}, #{item.debtorpayPaymentTypeCode, jdbcType=BIGINT}, #{item.debtorpayPaymentTypeName, jdbcType=VARCHAR}, #{item.paymentMethodCode, jdbcType=BIGINT}, #{item.paymentMethodName, jdbcType=VARCHAR}, #{item.fileNo, jdbcType=VARCHAR}, #{item.remark, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.createTimeNew}, #{item.bankId,jdbcType=BIGINT}, #{item.bankName,jdbcType=VARCHAR} FROM DUAL
)
